@page "/book-appointment"
@rendermode InteractiveServer
@using sv_a2f08cf6bb4e4723b846a554cec29273.Services
@inject AppointmentService AppointmentSvc

<PageTitle>Book Appointment</PageTitle>

<h1>Book a Medical Appointment</h1>

<EditForm Model="@model" OnValidSubmit="HandleSubmit" FormName="bookAppointment">
    <DataAnnotationsValidator />

    @* STEP 1: Patient Information *@
    <fieldset>
        <legend>Step 1: Patient Information</legend>

        <div class="mb-3">
            <label for="patientName" class="form-label">Patient Name</label>
            <InputText id="patientName" class="form-control" @bind-Value="model.PatientName" />
            <ValidationMessage For="@(() => model.PatientName)" />
        </div>

        <div class="mb-3">
            <label for="email" class="form-label">Email</label>
            <InputText id="email" class="form-control" @bind-Value="model.Email" />
            <ValidationMessage For="@(() => model.Email)" />
            @if (serverErrors.ContainsKey(nameof(model.Email)))
            {
                <div class="validation-message">@serverErrors[nameof(model.Email)]</div>
            }
        </div>

        <div class="mb-3">
            <label for="phone" class="form-label">Phone</label>
            <InputText id="phone" class="form-control" @bind-Value="model.Phone" />
            <ValidationMessage For="@(() => model.Phone)" />
        </div>

        <div class="mb-3">
            <label for="insurance" class="form-label">Insurance Provider</label>
            <InputSelect id="insurance" class="form-select" @bind-Value="model.InsuranceProvider">
                <option value="">-- Select --</option>
                <option value="Aetna">Aetna</option>
                <option value="BlueCross">BlueCross</option>
                <option value="Cigna">Cigna</option>
                <option value="UnitedHealth">UnitedHealth</option>
                <option value="None">None</option>
            </InputSelect>
            <ValidationMessage For="@(() => model.InsuranceProvider)" />
        </div>

        @if (!showStep2)
        {
            <button type="button" class="btn btn-primary" @onclick="ProceedToStep2">Next</button>
        }
    </fieldset>

    @* STEP 2: Appointment Details *@
    @if (showStep2)
    {
        <fieldset class="mt-4">
            <legend>Step 2: Appointment Details</legend>

            <div class="mb-3">
                <label for="doctor" class="form-label">Preferred Doctor</label>
                <InputSelect id="doctor" class="form-select" @bind-Value="model.PreferredDoctor"
                    @bind-Value:after="OnDoctorOrDateChanged">
                    <option value="">-- Select --</option>
                    @foreach (var doc in doctors)
                    {
                        <option value="@doc">@doc</option>
                    }
                </InputSelect>
                <ValidationMessage For="@(() => model.PreferredDoctor)" />
                @if (serverErrors.ContainsKey(nameof(model.PreferredDoctor)))
                {
                    <div class="validation-message">@serverErrors[nameof(model.PreferredDoctor)]</div>
                }
            </div>

            <div class="mb-3">
                <label for="date" class="form-label">Date</label>
                <InputDate id="date" class="form-control" @bind-Value="model.AppointmentDate"
                    @bind-Value:after="OnDoctorOrDateChanged" />
                <ValidationMessage For="@(() => model.AppointmentDate)" />
            </div>

            <div class="mb-3">
                <label for="timeslot" class="form-label">Time Slot</label>
                <InputSelect id="timeslot" class="form-select" @bind-Value="model.TimeSlot">
                    <option value="">-- Select --</option>
                    @foreach (var slot in availableSlots)
                    {
                        <option value="@slot">@slot</option>
                    }
                </InputSelect>
                <ValidationMessage For="@(() => model.TimeSlot)" />
                @if (serverErrors.ContainsKey(nameof(model.TimeSlot)))
                {
                    <div class="validation-message">@serverErrors[nameof(model.TimeSlot)]</div>
                }
            </div>

            <div class="mb-3">
                <label for="reason" class="form-label">Reason for Visit</label>
                <InputTextArea id="reason" class="form-control" @bind-Value="model.ReasonForVisit" rows="3" />
                <ValidationMessage For="@(() => model.ReasonForVisit)" />
            </div>

            <button type="button" class="btn btn-secondary me-2" @onclick="CheckAvailability" disabled="@isSubmitting">
                Check Availability
            </button>
            <button type="submit" class="btn btn-success" disabled="@(!availabilityChecked || isSubmitting)">
                Book Appointment
            </button>
        </fieldset>
    }
</EditForm>

@if (bookingConfirmed)
{
    <div class="alert alert-success mt-4">
        Appointment booked successfully!
    </div>
}

@code {
    private AppointmentModel model = new();
    private List<string> doctors = [];
    private List<string> availableSlots = [];
    private Dictionary<string, string> serverErrors = new();
    private bool showStep2;
    private bool availabilityChecked;
    private bool isSubmitting;
    private bool bookingConfirmed;

    private EditContext? editContext;

    protected override async Task OnInitializedAsync()
    {
        doctors = await AppointmentSvc.GetDoctorsAsync();
        editContext = new EditContext(model);
    }

    private void ProceedToStep2()
    {
        editContext ??= new EditContext(model);
        var validationContext = new ValidationContext(model);
        var results = new List<System.ComponentModel.DataAnnotations.ValidationResult>();

        // Validate only step 1 fields
        bool step1Valid = true;
        step1Valid &= Validator.TryValidateProperty(model.PatientName,
            new ValidationContext(model) { MemberName = nameof(model.PatientName) }, results);
        step1Valid &= Validator.TryValidateProperty(model.Email,
            new ValidationContext(model) { MemberName = nameof(model.Email) }, results);
        step1Valid &= Validator.TryValidateProperty(model.Phone,
            new ValidationContext(model) { MemberName = nameof(model.Phone) }, results);
        step1Valid &= Validator.TryValidateProperty(model.InsuranceProvider,
            new ValidationContext(model) { MemberName = nameof(model.InsuranceProvider) }, results);

        if (step1Valid)
        {
            showStep2 = true;
        }
        else
        {
            editContext.NotifyValidationStateChanged();
        }
    }

    private async Task OnDoctorOrDateChanged()
    {
        availabilityChecked = false;
        serverErrors.Remove(nameof(model.PreferredDoctor));
        serverErrors.Remove(nameof(model.TimeSlot));

        if (!string.IsNullOrEmpty(model.PreferredDoctor) && model.AppointmentDate.HasValue)
        {
            availableSlots = await AppointmentSvc.GetAvailableTimeSlotsAsync(
                model.PreferredDoctor, model.AppointmentDate.Value);
            model.TimeSlot = string.Empty;
        }
    }

    private async Task CheckAvailability()
    {
        serverErrors.Clear();
        availabilityChecked = false;

        if (string.IsNullOrEmpty(model.PreferredDoctor) || !model.AppointmentDate.HasValue ||
            string.IsNullOrEmpty(model.TimeSlot) || string.IsNullOrEmpty(model.ReasonForVisit))
        {
            // Trigger DataAnnotations validation for step 2 fields
            editContext?.NotifyValidationStateChanged();
            return;
        }

        isSubmitting = true;
        try
        {
            var errors = await AppointmentSvc.ValidatePatientAsync(
                model.Email, model.InsuranceProvider, model.PreferredDoctor, model.TimeSlot);

            if (errors.Count > 0)
            {
                serverErrors = errors;
            }
            else
            {
                availabilityChecked = true;
            }
        }
        finally
        {
            isSubmitting = false;
        }
    }

    private void HandleSubmit()
    {
        if (!availabilityChecked) return;
        bookingConfirmed = true;
    }
}

